import{_ as a,c as o,o as r,aj as e,ak as l,az as d,aA as i,aB as s,aC as u}from"./chunks/framework.CoirRWyn.js";const A=JSON.parse('{"title":"1.3 网络搜索","description":"","frontmatter":{},"headers":[],"relativePath":"module_1/1.3网络搜索 [ Web search ].md","filePath":"module_1/1.3网络搜索 [ Web search ].md"}'),n={name:"module_1/1.3网络搜索 [ Web search ].md"};function p(_,t,h,q,c,m){return r(),o("div",null,[...t[0]||(t[0]=[e('<p><img src="'+l+'" alt="alt text"></p><h1 id="_1-3-网络搜索" tabindex="-1">1.3 网络搜索 <a class="header-anchor" href="#_1-3-网络搜索" aria-label="Permalink to “1.3 网络搜索”">​</a></h1><p><img src="'+d+'" alt="alt text"></p><h2 id="知识截止日期" tabindex="-1">知识截止日期 <a class="header-anchor" href="#知识截止日期" aria-label="Permalink to “知识截止日期”">​</a></h2><p>AI 模型的训练在某个时间点停止，因此它的知识存在一个&quot;截止日期&quot;——也就是说，AI 只读取了截止日期之前的互联网内容，之后它的知识便被冻结在那个时间点上。</p><p>但世界不会停止运转，新的事件不断发生，新的电影上映，新的梗图诞生……</p><h2 id="网络搜索的触发" tabindex="-1">网络搜索的触发 <a class="header-anchor" href="#网络搜索的触发" aria-label="Permalink to “网络搜索的触发”">​</a></h2><p>以&quot;6 7 梗&quot;为例：如果你问 AI&quot;2025 年的 6 7 梗是什么&quot;，它很可能会主动进行网络搜索，然后告诉你这是一个在多个社交媒体平台上广泛流传的网络流行语。 <img src="'+i+'" alt="alt text"></p><p>触发网络搜索的关键在于提示词中的&quot;2025&quot;——这让 AI 意识到，这条信息可能出现在它的知识截止日期之后，因此需要从网络获取更新的内容。</p><p><strong>举例说明：</strong></p><ul><li>GPT-4.5 模型的知识截止日期是 2025 年 8 月</li><li>&quot;6 7 梗&quot;的搜索热度在该截止日期之后才开始爆发 <img src="'+s+'" alt="alt text"></li><li>因此，该模型对这个梗并不了解，需要借助网络搜索来回答</li></ul><h2 id="哪些问题会触发网络搜索" tabindex="-1">哪些问题会触发网络搜索？ <a class="header-anchor" href="#哪些问题会触发网络搜索" aria-label="Permalink to “哪些问题会触发网络搜索？”">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>示例</th><th>是否触发搜索</th></tr></thead><tbody><tr><td>通用常识</td><td>手机掉进汤里怎么办？</td><td>通常不触发</td></tr><tr><td>通用常识</td><td>猫为什么盯着墙看？</td><td>通常不触发</td></tr><tr><td>历史知识</td><td>旅行者 1 号金唱片上有什么？</td><td>通常不触发</td></tr><tr><td>实时信息</td><td>最近发生了什么新闻？</td><td>触发搜索</td></tr><tr><td>位置信息</td><td>山景城附近评分最高的健身房？</td><td>触发搜索</td></tr><tr><td>小众信息</td><td>马凯特山奶酪滚坡赛是什么？</td><td>触发搜索</td></tr></tbody></table><blockquote><p>马凯特山奶酪滚坡赛是一项有趣的活动——参与者追着一个滚下山坡的奶酪轮子跑。</p></blockquote><h2 id="触发网络搜索的两种方式" tabindex="-1">触发网络搜索的两种方式 <a class="header-anchor" href="#触发网络搜索的两种方式" aria-label="Permalink to “触发网络搜索的两种方式”">​</a></h2><p><img src="'+u+'" alt="alt text"></p><ol><li><strong>AI 自动判断</strong>：模型识别到问题可能需要实时或小众信息，自动发起搜索</li><li><strong>用户主动触发</strong>： <ul><li>点击 AI 界面中的搜索按钮</li><li>在提示词中明确写出&quot;请搜索网络&quot;或&quot;请联网查询&quot;</li></ul></li></ol><blockquote><p>注意：并非所有 AI 模型都支持网络搜索，但目前主流的 AI 产品（如 ChatGPT、Gemini、Claude）大多已具备这一能力。</p></blockquote><h2 id="网络搜索的局限性" tabindex="-1">网络搜索的局限性 <a class="header-anchor" href="#网络搜索的局限性" aria-label="Permalink to “网络搜索的局限性”">​</a></h2><p>网络搜索能让 AI 用更新的信息来补充其预训练知识，从而在许多任务上表现更好。</p><p>但和普通网络搜索一样，它也可能返回<strong>不可靠的来源</strong>。</p><p>因此，在使用 AI 进行网络搜索时，需要注意：</p><ul><li>引导 AI 使用更权威、更可靠的信息来源</li><li>对搜索结果保持批判性思维</li><li>必要时核实 AI 给出的信息</li></ul><hr><p>网络搜索功能让 AI 从&quot;百科全书&quot;升级成了&quot;实时记者&quot;，但这个升级并不是无代价的。</p><p><strong>关于&quot;年份触发&quot;的技巧</strong>：文中提到在提示词里加上年份（如&quot;2025 年&quot;）可以触发网络搜索，这是一个很实用的小技巧。更广泛地说，任何暗示&quot;时效性&quot;的词语都能起到类似效果，比如&quot;最新的&quot;、&quot;现在&quot;、&quot;今年&quot;、&quot;近期&quot;等。养成这个习惯，能让 AI 主动去获取更新的信息，而不是依赖可能已经过时的预训练知识。</p><p><strong>AI 搜索 vs. 自己搜索</strong>：两者最大的区别在于，AI 会帮你&quot;消化&quot;搜索结果，而不是把一堆链接甩给你。这在需要综合多个来源时特别有价值——但也意味着你看不到原始信息，AI 的&quot;消化&quot;过程可能引入偏差或遗漏细节。</p><p><strong>一个反直觉的现象</strong>：有时候，不触发网络搜索反而更好。如果你问的是一个经典的、稳定的知识点（比如某个数学定理或历史事件），预训练知识往往比网络搜索更可靠——因为网络上可能充斥着质量参差不齐的二手解读，而 AI 的预训练知识来自大量高质量文本的综合提炼。</p>',28)])])}const g=a(n,[["render",p]]);export{A as __pageData,g as default};
